import { DynamoDBClient } from '@aws-sdk/client-dynamodb';
import { DynamoDBDocumentClient, ScanCommand } from '@aws-sdk/lib-dynamodb';

// Structured logger (2.2) - inline since this Lambda does not use admin-auth layer
const _LL = { DEBUG: 0, INFO: 1, WARN: 2, ERROR: 3 };
const _ML = _LL[(process.env.LOG_LEVEL || 'INFO').toUpperCase()] ?? 1;
const createLogger = (svc) => {
  let _pk = {};
  const _l = (lvl, msg, ex = {}) => { if ((_LL[lvl]??0) >= _ML) console.log(JSON.stringify({ timestamp: new Date().toISOString(), level: lvl, service: svc, message: msg, ..._pk, ...ex })); };
  return { info: (m,e) => _l('INFO',m,e), warn: (m,e) => _l('WARN',m,e), error: (m,e) => _l('ERROR',m,e), debug: (m,e) => _l('DEBUG',m,e), appendKeys: (k) => { _pk = {..._pk,...k}; }, resetKeys: () => { _pk = {}; } };
};

const logger = createLogger('tenant-reader');

const client = new DynamoDBClient({});
const dynamodb = DynamoDBDocumentClient.from(client);

export const handler = async (event) => {
  logger.info('Event:', JSON.stringify(event, null, 2));
  
  const { RequestType, ResourceProperties } = event;
  const { TableName } = ResourceProperties;
  
  if (RequestType === 'Delete') {
    return {
      Status: 'SUCCESS',
      PhysicalResourceId: 'tenant-reader',
      Data: {}
    };
  }
  
  try {
    // Scan the tenant table to get all tenants
    const params = {
      TableName: TableName
    };
    
    const result = await dynamodb.send(new ScanCommand(params));
    const tenants = result.Items || [];
    
    logger.info('Found tenants:', JSON.stringify(tenants, null, 2));
    
    // Transform tenant data to the format needed
    const tenantData = tenants.map(tenant => ({
      tenantId: tenant.id,
      tenantName: tenant.name,
      userPoolId: tenant.userpool,
      endUserSpUrl: tenant.endUserSpUrl,
      extraAppUrl: tenant.extraappurl || '',
      samlProxy: tenant.samlproxy || true,
      samlIdPMetadataUrl: tenant.samlIdPMetadataUrl,
      endUserClientId: tenant.enduserclientid,
      region: tenant.region || process.env.AWS_REGION,
      spPortalDomain: `login.${tenant.tenantId}.${process.env.ROOT_DOMAIN_NAME}`
    }));
    
    return {
      Status: 'SUCCESS',
      PhysicalResourceId: 'tenant-reader',
      Data: {
        Tenants: JSON.stringify(tenantData),
        TenantCount: tenantData.length.toString()
      }
    };
  } catch (error) {
    logger.error('Error reading tenants:', error);
    return {
      Status: 'FAILED',
      PhysicalResourceId: 'tenant-reader',
      Reason: error.message
    };
  }
};
